const raw = $input.first().json;
const b = raw.body || raw;

const data = {
  vehicleValue: parseFloat(b.vehicleValue) || 0,
  loanPayoffAmount: parseFloat(b.loanPayoffAmount) || 0,
  creditScore: parseInt(b.creditScore) || 700,
  monthlyIncome: parseFloat(b.monthlyIncome || b.monthly_salary) || 0,
  existingEMI: parseFloat(b.existingEMI) || 0,
  loanTenure: parseInt(b.loanTenure) || 60,
  downPayment: parseFloat(b.downPayment) || 0,
  nationality: b.nationality || 'UAE',
  employmentMonths: parseInt(b.employmentMonths || b.employment_months) || 12
};

// --- CALCULATIONS ---
data.equity = data.vehicleValue - data.loanPayoffAmount;
data.equityStatus = data.equity >= 0 ? 'Positive' : 'Negative';

// Finance Tier
if (data.creditScore >= 720) data.financeTier = 'Prime Plus';
else if (data.creditScore >= 680) data.financeTier = 'Prime';
else if (data.creditScore >= 620) data.financeTier = 'Near Prime';
else data.financeTier = 'Subprime';

// DTI Ratio
const loanAmount = data.vehicleValue - data.downPayment;
const estimatedRate = data.creditScore >= 720 ? 2.99 : data.creditScore >= 680 ? 4.49 : data.creditScore >= 620 ? 6.99 : 9.99;
const monthlyRate = estimatedRate / 100 / 12;
const emi = loanAmount * monthlyRate / (1 - Math.pow(1 + monthlyRate, -data.loanTenure));
data.estimatedEMI = Math.round(emi);
data.estimatedRate = estimatedRate;
data.loanAmount = loanAmount;

data.dti = data.monthlyIncome > 0 ? ((data.existingEMI + emi) / data.monthlyIncome * 100).toFixed(1) : 'N/A';
data.dtiStatus = parseFloat(data.dti) <= 50 ? 'ELIGIBLE' : parseFloat(data.dti) <= 65 ? 'BORDERLINE' : 'HIGH_RISK';

// UAE Bank recommendations
data.recommendedBanks = [];
if (data.creditScore >= 700 && data.nationality === 'UAE') data.recommendedBanks.push('Emirates NBD', 'ADCB', 'FAB');
else if (data.creditScore >= 650) data.recommendedBanks.push('Mashreq', 'RAKBank', 'DIB');
else data.recommendedBanks.push('Al Hilal', 'Ajman Bank');

return [{ json: data }];

